1	type Item = {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	};
7	
8	type Customer = { yearsWithMHPCO: number };
9	
10	type Scenario = {
11	  customer: Customer;
12	  steps: { op: "quote"; items: Item[] }[];
13	};
14	
15	type ScenarioResult = {
16	  results: { premium: number }[];
17	};
18	
19	const PROCESSING_FEE = 5;
20	
21	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
22	
23	const firstInsuranceSurcharge = (premium: number): number =>
24	  premium * FIRST_INSURANCE_SURCHARGE_RATE;
25	
26	const COMPONENT_PREMIUM = 25;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: COMPONENT_PREMIUM,
34	  moonstone: COMPONENT_PREMIUM,
35	};
36	
37	const BLOCK_PREMIUM = 60;
38	
39	const isBlock = (count: number): boolean => count === 3;
40	
41	const countByType = (items: Item[]): Record<string, number> =>
42	  items.reduce<Record<string, number>>((counts, item) => {
43	    counts[item.type] = (counts[item.type] ?? 0) + 1;
44	    return counts;
45	  }, {});
46	
47	const premiumForGroup = (type: string, count: number): number =>
48	  isBlock(count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
49	
50	const basePremiumFor = (items: Item[]): number =>
51	  Object.entries(countByType(items)).reduce(
52	    (total, [type, count]) => total + premiumForGroup(type, count),
53	    0,
54	  );
55	
56	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
57	
58	const surchargeFor = (
59	  items: Item[],
60	  qualifies: (item: Item) => boolean,
61	  rate: number,
62	): number =>
63	  items.reduce(
64	    (total, item) =>
65	      total + (qualifies(item) ? BASE_PREMIUMS[item.type] * rate : 0),
66	    0,
67	  );
68	
69	const CURSE_SURCHARGE_RATE = 0.5;
70	
71	const isCursed = (item: Item): boolean => item.cursed === true;
72	
73	const curseSurchargeFor = (items: Item[]): number =>
74	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
75	
76	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
77	
78	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
79	
80	const isHighlyEnchanted = (item: Item): boolean =>
81	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD;
82	
83	const enchantmentSurchargeFor = (items: Item[]): number =>
84	  surchargeFor(items, isHighlyEnchanted, ENCHANTMENT_SURCHARGE_RATE);
85	
86	const discountFor = (
87	  qualifies: boolean,
88	  premium: number,
89	  rate: number,
90	): number => (qualifies ? premium * rate : 0);
91	
92	const LOYALTY_DISCOUNT_RATE = 0.2;
93	
94	const LOYALTY_YEARS_THRESHOLD = 2;
95	
96	const loyaltyDiscountFor = (customer: Customer, premium: number): number =>
97	  discountFor(
98	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
99	    premium,
100	    LOYALTY_DISCOUNT_RATE,
101	  );
102	
103	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
104	
105	const followUpDiscountFor = (isFollowUp: boolean, premium: number): number =>
106	  discountFor(isFollowUp, premium, FOLLOW_UP_DISCOUNT_RATE);
107	
108	const quotePremium = (
109	  customer: Customer,
110	  items: Item[],
111	  isFollowUp: boolean,
112	): number => {
113	  const basePremium = basePremiumFor(items);
114	  return roundUpToWholeGold(
115	    basePremium +
116	      curseSurchargeFor(items) +
117	      enchantmentSurchargeFor(items) +
118	      firstInsuranceSurcharge(basePremium) -
119	      loyaltyDiscountFor(customer, basePremium) -
120	      followUpDiscountFor(isFollowUp, basePremium) +
121	      PROCESSING_FEE,
122	  );
123	};
124	
125	export const runScenario = (scenario: Scenario): ScenarioResult => ({
126	  results: scenario.steps.map((step, index) => ({
127	    premium: quotePremium(scenario.customer, step.items, index > 0),
128	  })),
129	});
